def _model_attribute_association_to_nested(
    model_attribute_association: ModelAttributeAssociation,
) -> ModelAttributeAssociationNested:
    """Convert flat ModelAttributeAssociation to nested format."""
    attrs = ModelAttributeAssociationAttributes()
    _populate_model_attribute_association_attrs(attrs, model_attribute_association)
    # Categorize relationships by save semantic (REPLACE, APPEND, REMOVE)
    replace_rels, append_rels, remove_rels = categorize_relationships(
        model_attribute_association,
        _MODEL_ATTRIBUTE_ASSOCIATION_REL_FIELDS,
        ModelAttributeAssociationRelationshipAttributes,
    )
    return ModelAttributeAssociationNested(
        guid=model_attribute_association.guid,
        type_name=model_attribute_association.type_name,
        status=model_attribute_association.status,
        version=model_attribute_association.version,
        create_time=model_attribute_association.create_time,
        update_time=model_attribute_association.update_time,
        created_by=model_attribute_association.created_by,
        updated_by=model_attribute_association.updated_by,
        classifications=model_attribute_association.classifications,
        classification_names=model_attribute_association.classification_names,
        meanings=model_attribute_association.meanings,
        labels=model_attribute_association.labels,
        business_attributes=model_attribute_association.business_attributes,
        custom_attributes=model_attribute_association.custom_attributes,
        pending_tasks=model_attribute_association.pending_tasks,
        proxy=model_attribute_association.proxy,
        is_incomplete=model_attribute_association.is_incomplete,
        provenance_type=model_attribute_association.provenance_type,
        home_id=model_attribute_association.home_id,
        depth=model_attribute_association.depth,
        immediate_upstream=model_attribute_association.immediate_upstream,
        immediate_downstream=model_attribute_association.immediate_downstream,
        attributes=attrs,
        relationship_attributes=replace_rels,
        append_relationship_attributes=append_rels,
        remove_relationship_attributes=remove_rels,
    )


def _model_attribute_association_from_nested(
    nested: ModelAttributeAssociationNested,
) -> ModelAttributeAssociation:
    """Convert nested format to flat ModelAttributeAssociation."""
    attrs = (
        nested.attributes
        if nested.attributes is not UNSET
        else ModelAttributeAssociationAttributes()
    )
    # Merge relationships from all three buckets
    merged_rels = merge_relationships(
        nested.relationship_attributes,
        nested.append_relationship_attributes,
        nested.remove_relationship_attributes,
        _MODEL_ATTRIBUTE_ASSOCIATION_REL_FIELDS,
        ModelAttributeAssociationRelationshipAttributes,
    )
    return ModelAttributeAssociation(
        guid=nested.guid,
        type_name=nested.type_name,
        status=nested.status,
        version=nested.version,
        create_time=nested.create_time,
        update_time=nested.update_time,
        created_by=nested.created_by,
        updated_by=nested.updated_by,
        classifications=nested.classifications,
        classification_names=nested.classification_names,
        labels=nested.labels,
        business_attributes=nested.business_attributes,
        custom_attributes=nested.custom_attributes,
        pending_tasks=nested.pending_tasks,
        proxy=nested.proxy,
        is_incomplete=nested.is_incomplete,
        provenance_type=nested.provenance_type,
        home_id=nested.home_id,
        depth=nested.depth,
        immediate_upstream=nested.immediate_upstream,
        immediate_downstream=nested.immediate_downstream,
        **_extract_model_attribute_association_attrs(attrs),
        # Merged relationship attributes
        **merged_rels,
    )


def _model_attribute_association_to_nested_bytes(
    model_attribute_association: ModelAttributeAssociation, serde: Serde
) -> bytes:
    """Convert flat ModelAttributeAssociation to nested JSON bytes."""
    return serde.encode(
        _model_attribute_association_to_nested(model_attribute_association)
    )


def _model_attribute_association_from_nested_bytes(
    data: bytes, serde: Serde
) -> ModelAttributeAssociation:
    """Convert nested JSON bytes to flat ModelAttributeAssociation."""
    nested = serde.decode(data, ModelAttributeAssociationNested)
    return _model_attribute_association_from_nested(nested)


